class EventMapper:
    """Mapeia elementos para eventos corretos do Bubble"""

    EVENT_TYPES = {
        "Button": "ButtonClicked",
        "Input": "InputValueChanged",
        "Dropdown": "DropdownValueChanged",
        "Page": "PageLoaded",
        "Text": "ElementEvent",
        "Group": "ElementEvent"
    }

    @classmethod
    def get_event_type(cls, element_type: str, event: str = "click") -> str:
        """Retorna tipo de evento correto baseado no elemento"""
        if element_type == "Button" and event == "click":
            return "ButtonClicked"
        elif element_type == "Input":
            return "InputValueChanged"
        elif element_type == "Dropdown":
            return "DropdownValueChanged"
        elif element_type == "Page":
            return "PageLoaded"
        else:
            return "ElementEvent"

    @classmethod
    def build_workflow_body(cls, element_type: str, element_id: str, event: str = "click") -> dict:
        """Constrói body de workflow CORRETO baseado no tipo de elemento"""
        from bubble_sdk import BubbleIDGenerator

        event_type = cls.get_event_type(element_type, event)
        wf_id = BubbleIDGenerator.element_id()

        if event_type == "ButtonClicked":
            return {
                "id": wf_id,
                "%x": "ButtonClicked",
                "%p": {
                    "%ei": element_id
                },
                "actions": {}
            }
        elif event_type == "InputValueChanged":
            return {
                "id": wf_id,
                "%x": "InputValueChanged",
                "%p": {
                    "%ei": element_id
                },
                "actions": {}
            }
        elif event_type == "PageLoaded":
            return {
                "id": wf_id,
                "%x": "PageLoaded",
                "%p": {},
                "actions": {}
            }
        else:
            return {
                "id": wf_id,
                "%x": "ElementEvent",
                "%p": {
                    "%ei": element_id,
                    "%et": event,
                    "%eC": True
                },
                "actions": {}
            }


