    def update_name(self, context_name: str, element_name: str, new_name: str, dry_run: bool = False) -> bool:
        """
        Update element name (display name in Bubble editor).

        Args:
            context_name: Name of the reusable or page
            element_name: Current element name to search for
            new_name: New name to set
            dry_run: If True, show payload but don't send
        """
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)

        if not context_id:
            logger.error(f"'{context_name}' not found (tried reusable and page)")
            return False
        logger.success(f"Found {context_type}: {context_name} -> {context_id}")

        logger.info(f"Searching for element: '{element_name}'")
        result = self.discovery.find_element_by_name(context_id, element_name, context_type=context_type)

        if not result:
            logger.error(f"Element named '{element_name}' not found")
            return False
        logger.success(f"Found element at path: {result['path']}")

        # Build path array
        element_path = list(result.get("path") or [])
        path_array = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            element_id or element_key,
        )

        # Resolve element identifiers for local alias cache updates.
        element_payload = result.get("element", {}) if isinstance(result.get("element"), dict) else {}
        element_id = str(result.get("id") or element_payload.get("id") or "").strip()
        element_key = str(result.get("key") or (element_path[-1] if element_path else "") or "").strip()

        # Create payload: write both internal and display names.
        pb = PayloadBuilder(appname=self.appname)
        pb.add_set_data(path_array + ["%nm"], new_name)
        pb.add_set_data(path_array + ["%dn"], new_name)

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        # Send to webhook
        try:
            self._dispatch_payload(pb)
            # Keep local alias cache consistent so subsequent commands can resolve
            # the new name immediately without a full project refresh.
            cache_id = element_id or element_key
            if cache_id:
                self._cache_element_ref_alias(
                    context_id=context_id,
                    context_type=context_type,
                    alias_name=new_name,
                    element_id=cache_id,
                    element_key=element_key or None,
                    element_path=element_path or None,
                )
                # Keep old alias mapped as well for backward compatibility.
                self._cache_element_ref_alias(
                    context_id=context_id,
                    context_type=context_type,
                    alias_name=element_name,
                    element_id=cache_id,
                    element_key=element_key or None,
                    element_path=element_path or None,
                )
            logger.success(f"Successfully renamed element to: '{new_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def update_placeholder(self, context_name: str, element_name: str, new_placeholder: str, dry_run: bool = False) -> bool:
        """
        Update element placeholder text.

        Args:
            context_name: Name of the page or reusable
            element_name: Element name to search for
            new_placeholder: New placeholder text
            dry_run: If True, show payload but don't send
        """
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)

        if not context_id:
            logger.error(f"'{context_name}' not found (tried reusable and page)")
            return False
        logger.success(f"Found {context_type}: {context_name} -> {context_id}")

        logger.info(f"Searching for element: '{element_name}'")
        result = self.discovery.find_element_by_name(context_id, element_name, context_type=context_type)

        if not result:
            logger.error(f"Element named '{element_name}' not found")
            return False
        logger.success(f"Found element at path: {result['path']}")

        # Build path array
        path_array = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            str(result.get("id") or "").strip(),
        )

        # Create payload (preserve dynamic parts if present)
        element_props = result.get("element", {}).get("properties", {}) if isinstance(result, dict) else {}
        placeholder_expr = self._build_preserved_text_expr(element_props, None, new_placeholder, ["placeholder", "%ps"])

        pb = PayloadBuilder(appname=self.appname)
        # Bubble write path for placeholders is `%ps` (TextExpression in SDK format).
        pb.add_set_data(path_array + ["%p", "%ps"], placeholder_expr)
        # Mirror to parsed app-format key for compatibility with mixed caches/parsers.
        if isinstance(placeholder_expr, dict) and placeholder_expr.get("%x") == "TextExpression":
            pb.add_set_data(
                path_array + ["%p", "placeholder"],
                {
                    "type": "TextExpression",
                    "entries": placeholder_expr.get("%e", {"0": str(new_placeholder or "")}),
                },
            )

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        # Send to webhook
        try:
            self._dispatch_payload(pb)
            logger.success(f"Successfully updated placeholder to: '{new_placeholder}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def update_style(self, context_name: str, element_name: str, new_style: str, dry_run: bool = False, search_by_text: bool = False, keep_overrides: bool = False) -> bool:
        """Update an element's style"""
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)
        if not context_id:
            logger.error(f"'{context_name}' not found")
            return False

        logger.info(f"Searching for element: '{element_name}' (by_text={search_by_text})")

        result = None

        label_candidates: List[str] = []
        raw_name = str(element_name or "").strip()
        if raw_name:
            label_candidates.append(raw_name)
        if raw_name.lower().startswith("button "):
            stripped = raw_name[7:].strip()
            if stripped and stripped not in label_candidates:
                label_candidates.insert(0, stripped)
        for label_candidate in label_candidates:
            result = self._find_button_by_label(context_id, context_type, label_candidate)
            if result:
                logger.info(f"Resolved '{element_name}' by button label.")
                break

        # 1. Search by text if requested
        if search_by_text and not result:
             result = self.discovery.find_element_by_text(context_id, element_name, context_type=context_type)
             if result:
                 logger.success("Found element by text content.")

        # 2. Search by name (if not found by text or not requested)
        if not result:
            result = self.discovery.find_element_by_name(context_id, element_name, context_type=context_type)

        # 3. Fallback to search by text (if name search failed and wasn't already tried)
        if not result and not search_by_text:
            # Fallback to search by text
            result = self.discovery.find_element_by_text(context_id, element_name, context_type=context_type)

        if not result and not search_by_text:
            # Extra fallback: if element label starts with "Text ", search by its text content
            if element_name.lower().startswith("text "):
                alt_text = element_name[5:].strip()
                if alt_text:
                    result = self.discovery.find_element_by_text(context_id, alt_text, context_type=context_type)

        if not result and not search_by_text:
            # Extra fallback: handle labels like "Text content2's content's" (dynamic GetElement)
            label = element_name.strip()
            if label.lower().startswith("text "):
                label = label[5:].strip()
            source_match = re.split(r"['’]s", label, maxsplit=1)
            if source_match and source_match[0].strip():
                result = self._find_text_element_by_source_name(context_id, context_type, source_match[0].strip())

        if not result:
            label_candidates: List[str] = []
            raw_name = str(element_name or "").strip()
            if raw_name:
                label_candidates.append(raw_name)
            if raw_name.lower().startswith("button "):
                stripped = raw_name[7:].strip()
                if stripped and stripped not in label_candidates:
                    label_candidates.insert(0, stripped)
            for label_candidate in label_candidates:
                result = self._find_button_by_label(context_id, context_type, label_candidate)
                if result:
                    logger.info(f"Resolved '{element_name}' by button label.")
                    break

        if not result:
            cached_payload = self._resolve_cached_element_alias(context_id, context_type, element_name)
            if cached_payload:
                logger.info(f"Resolved '{element_name}' via local alias cache.")
                result = cached_payload

        if not result and self._auto_sync_element_ref_aliases():
            cached_payload = self._resolve_cached_element_alias(context_id, context_type, element_name)
            if cached_payload:
                logger.info(f"Resolved '{element_name}' after auto-syncing alias cache.")
                result = cached_payload

        if not result:
            logger.error(f"Element '{element_name}' not found (by name, text, or cache alias)")
            return False

        element_id = str(result.get("id") or ((result.get("element") or {}).get("id") if isinstance(result.get("element"), dict) else "") or "").strip()
        if not element_id:
            logger.error(f"Could not resolve element id for '{element_name}'.")
            return False
        logger.success(f"Found element: {element_name} -> {element_id}")

        # Resolve Style ID
        final_style = self.find_style_id_by_name(new_style)

        # Build Payload
        pb = PayloadBuilder(appname=self.appname)

        # Path to element style property (%s1)
        path = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            element_id,
        )
        target_path = path + ["%s1"]

        # Clear style-driven overrides so the chosen style fully applies.
        element = result.get("element", {}) if isinstance(result, dict) else {}
        el_type = element.get("type") or element.get("%x")
        if not el_type:
            inferred_type = self._infer_element_type_from_style_id(final_style)
            if inferred_type:
                el_type = inferred_type
        if not keep_overrides:
            override_keys = self._style_override_keys_for_element_type(
                str(el_type or ""),
                target_style_id=final_style,
            )
            for key in override_keys:
                pb.add_set_data(path + ["%p", str(key)], None)
            self._queue_clear_style_marker_props(
                pb,
                path,
            )

        pb.add_set_data(target_path, final_style)

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        # Send
        try:
            self._dispatch_payload(pb)
            logger.success(f"Successfully updated style to: '{final_style}' (Original: {new_style})")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def _find_text_element_by_source_name(self, context_id: str, context_type: str, source_name: str) -> Optional[Dict[str, Any]]:
        """Try to find a Text element whose text expression references a source element by name."""
        def _norm(value: str) -> str:
            if value is None:
                return ""
            return str(value).replace("’", "'").replace("‘", "'").replace("`", "'").strip().lower()

        elements = self.discovery.list_elements(context_id, context_type=context_type)
        if not elements:
            return None

        id_to_name = {}
        # Include root element (page or reusable) in case GetElement references it
        root = None
        if context_type == "reusable":
            root = self.discovery.data.get("element_definitions", {}).get(context_id)
        else:
            root = self.discovery.data.get("pages", {}).get(context_id)
        if isinstance(root, dict):
            root_id = root.get("id")
            root_name = root.get("name") or root.get("default_name") or root.get("properties", {}).get("element_name")
            if root_id and root_name:
                id_to_name[root_id] = root_name

        for item in elements:
            el = item.get("element") or {}
            el_id = el.get("id")
            if not el_id:
                continue
            name = el.get("name") or el.get("default_name") or el.get("properties", {}).get("element_name")
            if name:
                id_to_name[el_id] = name

        target_id = None
        needle = _norm(source_name)
        for el_id, name in id_to_name.items():
            if needle and needle in _norm(name):
                target_id = el_id
                break

        if not target_id:
            return None

        for item in elements:
            el = item.get("element") or {}
            if el.get("type") != "Text" and el.get("%x") != "Text":
                continue
            props = el.get("properties", {})
            text_prop = props.get("text", {})
            entries = text_prop.get("entries") if isinstance(text_prop, dict) else None
            if not isinstance(entries, dict):
                continue
            for v in entries.values():
                if isinstance(v, dict) and (v.get("type") == "GetElement" or v.get("%x") == "GetElement"):
                    gprops = v.get("properties") or v.get("%p") or {}
                    if gprops.get("element_id") == target_id:
                        return {"path": item.get("path"), "id": el.get("id"), "element": el}

        return None


    def update_image(self, context_name: str, element_name: str, new_source: str, dry_run: bool = False, prefer_last: bool = False) -> bool:
        """Update image source for an Image element."""
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)
        if not context_id:
            logger.error(f"'{context_name}' not found")
            return False

        logger.info(f"Searching for image element: '{element_name}'")
        result = self.discovery.find_element_by_name(
            context_id, element_name, context_type=context_type, prefer_last=prefer_last
        )

        def _is_image_match(item: Dict[str, Any]) -> bool:
            if not isinstance(item, dict):
                return False
            el = item.get("element", {}) if isinstance(item.get("element"), dict) else {}
            el_type = str(el.get("type") or el.get("%x") or "").strip().lower()
            return el_type == "image"

        # Fallback: ref lookup across discovery/raw/module/index data.
        if not result or not _is_image_match(result):
            matches = self._find_elements_by_ref(
                context_id,
                context_type,
                element_name,
                ref_kind="auto",
            )
            image_matches = [m for m in matches if _is_image_match(m)]
            if image_matches:
                result = image_matches[-1] if prefer_last else image_matches[0]
                logger.info(f"Resolved image '{element_name}' via reference lookup.")

        # Fallback: local alias cache.
        if not result:
            cached_payload = self._resolve_cached_element_alias(context_id, context_type, element_name)
            if cached_payload:
                result = cached_payload
                logger.info(f"Resolved image '{element_name}' via local alias cache.")

        # Fallback: auto-sync element aliases and retry cache.
        if not result and self._auto_sync_element_ref_aliases():
            cached_payload = self._resolve_cached_element_alias(context_id, context_type, element_name)
            if cached_payload:
                result = cached_payload
                logger.info(f"Resolved image '{element_name}' after auto-syncing alias cache.")

        if not result:
            logger.error(f"Image element '{element_name}' not found (by name/ref/cache)")
            # Helpful hint: list same-name image matches in other contexts.
            suggestions: List[str] = []
            suggestion_seen: set[str] = set()
            try:
                for ctx in self._iter_contexts(scope="all"):
                    cid = str(ctx.get("id") or "").strip()
                    ctype = str(ctx.get("type") or "").strip() or "page"
                    cname = str(ctx.get("name") or cid).strip() or cid
                    if not cid or (cid == context_id and ctype == context_type):
                        continue
                    try:
                        matches = self._find_elements_by_ref(cid, ctype, element_name, ref_kind="name")
                    except Exception:
                        continue
                    for m in matches:
                        el = m.get("element", {}) if isinstance(m.get("element"), dict) else {}
                        if str(el.get("type") or el.get("%x") or "").strip().lower() != "image":
                            continue
                        key = f"{ctype}:{cname}"
                        if key in suggestion_seen:
                            continue
                        suggestion_seen.add(key)
                        suggestions.append(key)
                        if len(suggestions) >= 5:
                            break
                    if len(suggestions) >= 5:
                        break
            except Exception:
                suggestions = []
            if suggestions:
                logger.info(
                    "Found similarly named image element(s) in other contexts: "
                    + ", ".join(suggestions)
                )
            return False

        element = result.get("element", {})
        el_type = element.get("type") or element.get("%x")
        if el_type and el_type.lower() != "image":
            logger.warning(f"Target element is type '{el_type}', updating src anyway.")

        path = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            str(result.get("id") or ((result.get("element") or {}).get("id") if isinstance(result.get("element"), dict) else "") or "").strip(),
        )

        def _option_value_expr(option_set: Optional[str], option_value: str, next_node: Optional[Dict[str, Any]]) -> Dict[str, Any]:
            opt_node = {
                "%x": "OptionValue",
                "%p": {},
                "%n": None
            }
            if option_set:
                opt_node["%p"]["option_set"] = option_set
            if option_value:
                opt_node["%p"]["option_value"] = option_value
            if next_node:
                opt_node["%n"] = next_node
            return {
                "%x": "TextExpression",
                "%e": {"0": opt_node}
            }

        # Inspect current src to preserve dynamic Option Set logic when present
        src_expr = None
        props = element.get("properties", {}) if isinstance(element, dict) else {}
        current_src = props.get("src")

        if isinstance(current_src, dict):
            entries = current_src.get("entries") or current_src.get("%e")
            if isinstance(entries, dict):
                # Bubble app.bubble uses entries["0"] with OptionValue
                opt_node = entries.get("0") or entries.get("1")
                if isinstance(opt_node, dict) and (opt_node.get("type") == "OptionValue" or opt_node.get("%x") == "OptionValue"):
                    opt_props = opt_node.get("properties") or opt_node.get("%p") or {}
                    option_set = opt_props.get("option_set")
                    # Keep existing option_set, update option_value
                    next_node = opt_node.get("next") or opt_node.get("%n")
                    if next_node and next_node.get("type") == "Message":
                        next_node = {
                            "%x": "Message",
                            "%nm": next_node.get("name"),
                            "%n": None,
                            "%a": None,
                            "is_slidable": False
                        }
                    elif isinstance(next_node, dict) and next_node.get("%x") == "Message":
                        pass
                    elif next_node is None and opt_node.get("%n") is not None:
                        next_node = opt_node.get("%n")

                    # Default next node to "file" if missing
                    if not next_node and option_set:
                        next_node = {
                            "%x": "Message",
                            "%nm": "file",
                            "%n": None,
                            "%a": None,
                            "is_slidable": False
                        }

                    src_expr = _option_value_expr(option_set, new_source, next_node)

        if src_expr is None:
            src_expr = {
                "%x": "TextExpression",
                "%e": {"0": new_source}
            }

        pb = PayloadBuilder(appname=self.appname)
        pb.add_set_data(path + ["%p", "src"], src_expr)

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        try:
            self._dispatch_payload(pb)
            logger.success(f"Successfully updated image '{element_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def _find_button_by_label(self, context_id: str, context_type: str, label: str) -> Optional[Dict[str, Any]]:
        """Find a Button element whose label text matches the given label."""
        def _norm(value: str) -> str:
            if value is None:
                return ""
            return str(value).replace("’", "'").replace("‘", "'").replace("`", "'").strip().lower()

        needle = _norm(label)
        if not needle:
            return None

        candidate_items: List[Dict[str, Any]] = []
        seen_candidates: set[str] = set()
        for source_items in (
            self.discovery.list_elements(context_id, context_type=context_type),
            self._list_raw_context_elements(context_id, context_type),
            self._list_module_context_elements(context_id, context_type),
            self._list_index_context_elements(context_id, context_type),
        ):
            if not isinstance(source_items, list):
                continue
            for item in source_items:
                if not isinstance(item, dict):
                    continue
                item_id = str(item.get("id") or ((item.get("element") or {}).get("id") if isinstance(item.get("element"), dict) else "") or "").strip()
                item_path = str(item.get("path") or "").strip()
                dedupe_key = f"{item_id}|{item_path}"
                if dedupe_key in seen_candidates:
                    continue
                seen_candidates.add(dedupe_key)
                candidate_items.append(item)

        for item in candidate_items:
            el = item.get("element") or {}
            if el.get("type") != "Button" and el.get("%x") != "Button":
                continue
            content = ""

            # Legacy parsed structure: properties.text.entries
            props = el.get("properties", {})
            text_prop = props.get("text")
            entries = text_prop.get("entries") if isinstance(text_prop, dict) else None
            if isinstance(entries, dict):
                parts = []
                for k in sorted(entries.keys(), key=lambda x: int(x) if str(x).isdigit() else 0):
                    v = entries[k]
                    if isinstance(v, str):
                        parts.append(v)
                content = "".join(parts)

            # Raw Bubble structure: %p.%3 TextExpression
            if not content:
                p = el.get("%p", {}) if isinstance(el.get("%p"), dict) else {}
                txt_expr = p.get("%3")
                if isinstance(txt_expr, dict):
                    parts = txt_expr.get("%e")
                    if isinstance(parts, dict):
                        ordered = []
                        for k in sorted(parts.keys(), key=lambda x: int(x) if str(x).isdigit() else 0):
                            v = parts.get(k)
                            if isinstance(v, str):
                                ordered.append(v)
                        content = "".join(ordered)

            if needle in _norm(content):
                return {"path": item.get("path"), "id": el.get("id"), "element": el}

        return None

    def _find_icon_by_signature(self, context_id: str, context_type: str, signature: str) -> Optional[Dict[str, Any]]:
        """Find an Icon/Button element by name or icon value signature."""
        def _norm(value: str) -> str:
            if value is None:
                return ""
            return str(value).replace("’", "'").replace("‘", "'").replace("`", "'").strip().lower()

        needle = _norm(signature)
        if not needle:
            return None
        if needle.startswith("icon "):
            needle = needle[5:].strip()

        best = None
        best_score = 0

        elements = self.discovery.list_elements(context_id, context_type=context_type)
        for item in elements:
            el = item.get("element") or {}
            el_type = (el.get("type") or el.get("%x") or "").lower()
            if el_type not in ["icon", "button"]:
                continue

            props = el.get("properties", {}) if isinstance(el, dict) else {}
            candidates = [
                el.get("name"),
                el.get("default_name"),
                props.get("element_name"),
                props.get("icon"),
                props.get("%9i")
            ]
            score = 0
            for cand in candidates:
                cand_n = _norm(cand)
                if not cand_n:
                    continue
                if needle == cand_n:
                    score = max(score, 100)
                elif needle in cand_n:
                    score = max(score, 90)
                elif cand_n in needle:
                    score = max(score, 70)
                else:
                    # Token overlap fallback helps with truncated names like "lis" vs "list"
                    ntoks = [t for t in needle.split() if t]
                    ctoks = [t for t in cand_n.split() if t]
                    overlap = len(set(ntoks).intersection(ctoks))
                    if overlap >= 2:
                        score = max(score, 50 + overlap)
                    elif overlap == 1:
                        # Prefix token match (lis ~ list)
                        if any(c.startswith(nt) for nt in ntoks for c in ctoks if len(nt) >= 3):
                            score = max(score, 45)

            if score > best_score:
                best_score = score
                best = {"path": item.get("path"), "id": el.get("id"), "element": el}

        return best if best_score >= 45 else None

    @staticmethod
    def _slug_icon_name(icon_name: str) -> str:
        part = str(icon_name or "").strip().lower()
        part = re.sub(r"[\s_]+", "-", part)
        part = re.sub(r"[^a-z0-9-]", "", part)
        part = re.sub(r"-{2,}", "-", part)
        return part.strip("-")

    def _resolve_icon_prefix(self, icon_value: Optional[str], allow_fallback: bool = False) -> str:
        if not icon_value:
            return ""
        raw = str(icon_value).strip().lower()
        raw = re.sub(r"\s+", " ", raw).strip()
        known_prefixes = [
            "phosphor regular",
            "phosphor fill",
            "phosphor duotone",
            "phosphor bold",
            "phosphor light",
            "phosphor thin",
            "material outlined",
            "material rounded",
            "material sharp",
            "heroicons outline",
            "heroicons solid",
            "feather",
            "ion",
        ]
        for prefix in known_prefixes:
            if raw == prefix or raw.startswith(prefix + " "):
                return prefix
        if not allow_fallback:
            return ""
        parts = raw.split()
        if len(parts) >= 2:
            return " ".join(parts[:2])
        return parts[0] if parts else ""

    def _normalize_icon_value_for_write(
        self,
        incoming: Optional[str],
        *,
        existing_icon: Optional[str] = None,
        default_library: Optional[str] = None,
    ) -> Optional[str]:
        """
        Normalize icon identifiers to Bubble editor format.
        Canonical format: "<library> <variant?> <icon-name>"
        Example: "phosphor regular check-circle"
        """
        if incoming is None:
            return None

        raw = str(incoming).strip().lower()
        while len(raw) >= 2 and ((raw[0] == raw[-1] and raw[0] in {'"', "'"}) or (raw[0], raw[-1]) in {("“", "”"), (""", "”"), ("“", """)}):
            raw = raw[1:-1].strip()
        if not raw:
            return raw

        # Preserve FontAwesome class notation.
        if raw.startswith(("fa ", "fas ", "far ", "fab ")):
            return re.sub(r"\s+", " ", raw).strip()

        normalized = raw.replace("/", " ").replace(":", " ")
        normalized = re.sub(r"\s+", " ", normalized).strip()

        explicit_prefix = self._resolve_icon_prefix(normalized, allow_fallback=False)
        if explicit_prefix:
            remainder = normalized[len(explicit_prefix):].strip()
            if remainder:
                return f"{explicit_prefix} {self._slug_icon_name(remainder)}"
            return explicit_prefix

        # Library provided without required variant: apply defaults.
        if normalized.startswith("phosphor "):
            remainder = normalized[len("phosphor "):].strip()
            return (
                f"phosphor regular {self._slug_icon_name(remainder)}"
                if remainder
                else "phosphor regular"
            )
        if normalized.startswith("material "):
            remainder = normalized[len("material "):].strip()
            return (
                f"material outlined {self._slug_icon_name(remainder)}"
                if remainder
                else "material outlined"
            )
        if normalized.startswith("heroicons "):
            remainder = normalized[len("heroicons "):].strip()
            return (
                f"heroicons outline {self._slug_icon_name(remainder)}"
                if remainder
                else "heroicons outline"
            )
        if normalized.startswith("feather "):
            remainder = normalized[len("feather "):].strip()
            return f"feather {self._slug_icon_name(remainder)}" if remainder else "feather"
        if normalized.startswith("ion "):
            remainder = normalized[len("ion "):].strip()
            return f"ion {self._slug_icon_name(remainder)}" if remainder else "ion"

        inherited_prefix = self._resolve_icon_prefix(existing_icon, allow_fallback=True)
        if not inherited_prefix and default_library:
            lib = str(default_library).strip().lower()
            if lib == "phosphor":
                inherited_prefix = "phosphor regular"
            elif lib == "material":
                inherited_prefix = "material outlined"
            elif lib == "heroicons":
                inherited_prefix = "heroicons outline"
            elif lib in {"feather", "ion"}:
                inherited_prefix = lib

        if inherited_prefix:
            return f"{inherited_prefix} {self._slug_icon_name(normalized)}"

        return normalized

    def update_icon(self, context_name: str, element_name: str, new_icon: str, dry_run: bool = False, prefer_last: bool = False) -> bool:
        """Update icon for Icon/Button elements."""
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)
        if not context_id:
            logger.error(f"'{context_name}' not found")
            return False

        logger.info(f"Searching for icon element: '{element_name}'")
        result = self.discovery.find_element_by_name(
            context_id, element_name, context_type=context_type, prefer_last=prefer_last
        )
        if not result:
            result = self._find_icon_by_signature(context_id, context_type, element_name)
        if not result:
            logger.error(f"Icon element '{element_name}' not found")
            return False

        element = result.get("element", {})
        props = element.get("properties", {}) if isinstance(element, dict) else {}
        existing_icon = props.get("icon") or props.get("%9i")
        resolved_icon = self._normalize_icon_value_for_write(
            new_icon,
            existing_icon=existing_icon,
        )

        # Bubble expects icon updates through %9i in SetData payloads.
        key = "%9i"
        path = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            str(result.get("id") or ((result.get("element") or {}).get("id") if isinstance(result.get("element"), dict) else "") or "").strip(),
        )

        pb = PayloadBuilder(appname=self.appname)
        pb.add_set_data(path + ["%p", key], resolved_icon)

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        try:
            self._dispatch_payload(pb)
            logger.success(f"Successfully updated icon '{element_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def _resolve_element_for_updates(
        self,
        context_name: str,
        element_name: str,
        *,
        prefer_last: bool = False,
    ) -> Optional[Tuple[str, str, Dict[str, Any]]]:
        """Resolve context + element robustly for update operations."""
        logger.info(f"Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)
        if not context_id:
            logger.error(f"'{context_name}' not found")
            return None

        logger.info(f"Searching for element: '{element_name}'")
        result = self.discovery.find_element_by_name(
            context_id,
            element_name,
            context_type=context_type,
            prefer_last=prefer_last,
        )
        if not result:
            label_candidates: List[str] = []
            raw_name = str(element_name or "").strip()
            if raw_name:
                label_candidates.append(raw_name)
            if raw_name.lower().startswith("button "):
                stripped = raw_name[7:].strip()
                if stripped and stripped not in label_candidates:
                    label_candidates.insert(0, stripped)
            for label_candidate in label_candidates:
                result = self._find_button_by_label(context_id, context_type, label_candidate)
                if result:
                    logger.info(f"Resolved '{element_name}' by button label.")
                    break
        if not result:
            result = self._find_element_by_ref(
                context_id,
                context_type,
                element_name,
                ref_kind="auto",
                match_index=1,
            )
            if result:
                logger.info(f"Resolved '{element_name}' by reference lookup.")
        if not result:
            result = self._resolve_cached_element_alias(context_id, context_type, element_name)
            if result:
                logger.info(f"Resolved '{element_name}' via local alias cache.")
        if not result:
            logger.error(f"Element '{element_name}' not found")
            return None

        # Alias/cache lookups may return only id/path metadata. Hydrate the
        # full element object from discovery so update flows can access raw %p.
        if isinstance(result, dict):
            hydrated_element = result.get("element")
            needs_hydration = (
                not isinstance(hydrated_element, dict)
                or not hydrated_element
                or (
                    not isinstance(hydrated_element.get("%p"), dict)
                    and not isinstance(hydrated_element.get("properties"), dict)
                )
            )
            candidate_path = result.get("path")
            if needs_hydration and isinstance(candidate_path, list) and candidate_path:
                resolved_path = self.discovery.build_path_array(
                    context_id,
                    candidate_path,
                    context_type=context_type,
                )
                resolved_node = self._get_value_at_path(resolved_path)
                if isinstance(resolved_node, dict):
                    hydrated_result = dict(result)
                    hydrated_result["element"] = resolved_node
                    if not hydrated_result.get("id"):
                        resolved_id = str(resolved_node.get("id") or "").strip()
                        if resolved_id:
                            hydrated_result["id"] = resolved_id
                    result = hydrated_result

            # Secondary hydration fallback: resolve from normalized element list.
            hydrated_element = result.get("element") if isinstance(result, dict) else None
            still_missing_props = (
                not isinstance(hydrated_element, dict)
                or (
                    not isinstance(hydrated_element.get("%p"), dict)
                    and not isinstance(hydrated_element.get("properties"), dict)
                )
            )
            if still_missing_props:
                target_id = str(result.get("id") or result.get("key") or "").strip()
                target_path = result.get("path")
                try:
                    candidate_elements = self.discovery.list_elements(context_id, context_type=context_type) or []
                except Exception:
                    candidate_elements = []
                matched_item: Optional[Dict[str, Any]] = None
                if isinstance(candidate_elements, list):
                    if target_id:
                        for item in candidate_elements:
                            if not isinstance(item, dict):
                                continue
                            item_element = item.get("element")
                            item_id = ""
                            if isinstance(item_element, dict):
                                item_id = str(item_element.get("id") or "").strip()
                            if not item_id:
                                item_id = str(item.get("id") or "").strip()
                            if item_id and item_id == target_id:
                                matched_item = item
                                break
                    if matched_item is None and isinstance(target_path, list):
                        for item in candidate_elements:
                            if isinstance(item, dict) and item.get("path") == target_path:
                                matched_item = item
                                break
                if isinstance(matched_item, dict):
                    hydrated_result = dict(result)
                    item_element = matched_item.get("element")
                    if isinstance(item_element, dict):
                        hydrated_result["element"] = item_element
                        if not hydrated_result.get("id"):
                            resolved_id = str(item_element.get("id") or "").strip()
                            if resolved_id:
                                hydrated_result["id"] = resolved_id
                    if not hydrated_result.get("path") and isinstance(matched_item.get("path"), list):
                        hydrated_result["path"] = matched_item.get("path")
                    result = hydrated_result

        return context_id, context_type, result

    @staticmethod
    def _normalize_element_type_token(value: Any) -> str:
        token = str(value or "").strip().lower()
        return re.sub(r"[^a-z0-9]+", "", token)

    def _element_type_matches(self, actual_type: Any, expected_type: Any) -> bool:
        actual = self._normalize_element_type_token(actual_type)
        expected = self._normalize_element_type_token(expected_type)
        if not expected:
            return True
        aliases: Dict[str, set] = {
            "group": {"group"},
            "floatinggroup": {"floatinggroup"},
            "groupfocus": {"groupfocus"},
            "popup": {"popup"},
            "repeatinggroup": {"repeatinggroup"},
            "table": {"table"},
            "shape": {"shape"},
            "alert": {"alert"},
            "video": {"videoplayer", "video"},
            "html": {"html"},
            "map": {"googlemap", "map"},
            "input": {"input"},
            "multilineinput": {"multilineinput"},
            "checkbox": {"checkbox"},
            "dropdown": {"dropdown"},
            "searchbox": {"autocompletedropdown", "searchbox"},
            "radio": {"radiobuttons", "radio"},
            "slider": {"slider"},
            "datepicker": {"datepicker"},
            "fileuploader": {"fileuploader"},
            "image": {"image"},
            "pictureuploader": {"image", "pictureuploader"},
            "datetimepicker": {"datepicker", "datetimepicker"},
        }
        allowed = aliases.get(expected, {expected})
        return actual in allowed

    @staticmethod
    def _coerce_int_px_value(raw_value: Any) -> Optional[int]:
        if raw_value is None or isinstance(raw_value, bool):
            return None
        if isinstance(raw_value, (int, float)):
            return int(raw_value)
        raw = str(raw_value).strip().lower()
        if raw.endswith("px"):
            raw = raw[:-2].strip()
        if re.fullmatch(r"-?\d+(?:\.\d+)?", raw):
            try:
                return int(float(raw))
            except Exception:
                return None
        return None

    @staticmethod
    def _coerce_css_length_value(raw_value: Any) -> Optional[str]:
        return ElementBuilder._normalize_css_length(raw_value)

    def _apply_dimension_updates(
        self,
        prop_updates: Dict[str, Any],
        *,
        width: Any = None,

        height: Any = None,
        min_width: Any = None,
        max_width: Any = None,
        fixed_width: Optional[bool] = None,
        fit_width: Optional[bool] = None,
        min_height: Any = None,
        max_height: Any = None,
        fixed_height: Optional[bool] = None,
        fit_height: Optional[bool] = None,
        include_fit: bool = True,
        set_wh_ints: bool = False,
    ) -> None:
        """Populate responsive/fixed sizing keys using create-command semantics."""
        if width is not None:
            normalized = self._coerce_css_length_value(width)
            if normalized is not None:
                prop_updates["min_width_css"] = normalized
            px_width = self._coerce_int_px_value(width)
            if set_wh_ints and px_width is not None:
                prop_updates["%w"] = px_width
        if height is not None:
            normalized = self._coerce_css_length_value(height)
            if normalized is not None:
                prop_updates["min_height_css"] = normalized
            px_height = self._coerce_int_px_value(height)
            if set_wh_ints and px_height is not None:
                prop_updates["%h"] = px_height

        if min_width is not None:
            normalized = self._coerce_css_length_value(min_width)
            if normalized is not None:

                prop_updates["min_width_css"] = normalized
        if max_width is not None:
            normalized = self._coerce_css_length_value(max_width)
            if normalized is not None:
                prop_updates["max_width_css"] = normalized
        if min_height is not None:
            normalized = self._coerce_css_length_value(min_height)
            if normalized is not None:
                prop_updates["min_height_css"] = normalized
        if max_height is not None:
            normalized = self._coerce_css_length_value(max_height)
            if normalized is not None:
                prop_updates["max_height_css"] = normalized

        if include_fit:
            if fit_width is not None:
                prop_updates["fit_width"] = bool(fit_width)
            if fit_height is not None:
                prop_updates["fit_height"] = bool(fit_height)

        if fixed_width is not None:
            prop_updates["single_width"] = bool(fixed_width)
            if fixed_width:
                source_val = width if width is not None else (min_width if min_width is not None else max_width)
                normalized = self._coerce_css_length_value(source_val)
                if normalized is not None:
                    prop_updates["min_width_css"] = normalized
                    prop_updates["max_width_css"] = normalized
                if include_fit:
                    prop_updates["fit_width"] = False
        if fixed_height is not None:
            prop_updates["single_height"] = bool(fixed_height)
            if fixed_height:
                source_val = height if height is not None else (min_height if min_height is not None else max_height)
                normalized = self._coerce_css_length_value(source_val)
                if normalized is not None:
                    prop_updates["min_height_css"] = normalized
                    prop_updates["max_height_css"] = normalized
                if include_fit:
                    prop_updates["fit_height"] = False

    def _apply_global_element_updates(
        self,
        prop_updates: Dict[str, Any],
        *,
        is_visible: Optional[bool] = None,
        collapse_when_hidden: Optional[bool] = None,
        html_id: Optional[str] = None,
        unique_id: Optional[str] = None,
    ) -> None:
        if is_visible is not None:
            prop_updates["%iv"] = bool(is_visible)
        if collapse_when_hidden is not None:
            prop_updates["collapse_when_hidden"] = bool(collapse_when_hidden)
        resolved_html_id = html_id if html_id is not None else unique_id
        if resolved_html_id is not None:
            prop_updates["unique_id"] = {"%x": "TextExpression", "%e": {"0": str(resolved_html_id)}}

    def _style_override_keys_for_element_type(
        self,
        element_type: Optional[str],
        *,
        target_style_id: Optional[str] = None,
    ) -> List[str]:
        """Collect style-driven property keys for a given element type."""
        normalized_type = self._normalize_element_type_token(element_type)
        if not normalized_type:
            return []

        keys: List[str] = []
        seen: set = set()

        def _add_key(key: Any) -> None:
            key_str = str(key or "").strip()
            if not key_str or key_str in {"%s1", "style"}:
                return
            if key_str in seen:
                return
            seen.add(key_str)
            keys.append(key_str)

        # Baseline visual/style keys used across style-capable elements.
        for key in self._alert_style_override_keys():
            _add_key(key)

        def _collect_from_style_obj(style_obj: Dict[str, Any]) -> None:
            if not isinstance(style_obj, dict):
                return
            style_type = str(style_obj.get("%x") or style_obj.get("type") or "").strip()
            if self._normalize_element_type_token(style_type) != normalized_type:
                return
            style_props = style_obj.get("%p")
            if isinstance(style_props, dict):
                for style_key in style_props.keys():
                    _add_key(style_key)

        styles_data = self.discovery.data.get("styles", {}) if isinstance(self.discovery.data, dict) else {}
        if isinstance(styles_data, dict):
            for style_obj in styles_data.values():
                _collect_from_style_obj(style_obj)

        cached_styles = self._cli_cache.get("styles", {}) if isinstance(self._cli_cache, dict) else {}
        if isinstance(cached_styles, dict):
            for style_obj in cached_styles.values():
                _collect_from_style_obj(style_obj)

        if target_style_id:
            target_style_props = self._get_base_style_props(str(target_style_id))
            if isinstance(target_style_props, dict):
                for style_key in target_style_props.keys():
                    _add_key(style_key)

        if normalized_type == "repeatinggroup":
            for key in ("%ss", "%sw", "%sc", "separator_style", "separator_width", "separator_color"):
                _add_key(key)

        # Clear both compressed and expanded aliases to prevent stale overrides.
        alias_map: Dict[str, List[str]] = {
            "%bas": ["background_style", "bg_style"],
            "%bgc": ["background_color", "bg_color", "bgcolor"],
            "%bgi": ["background_image", "bg_image"],
            "%bgf": ["background_gradient_color1", "gradient_color1"],
            "%bgt": ["background_gradient_color2", "gradient_color2"],
            "%bgd": ["background_gradient_style", "gradient_style"],
            "%bgp": ["background_repeat"],
            "%cb": ["center_background"],
            "%rbv": ["repeat_background_vertical"],
            "%rbh": ["repeat_background_horizontal"],
            "%bc": ["border_color"],
            "%bw": ["border_width"],
            "%bos": ["border_style"],
            "%br": ["border_roundness", "border_radius"],
            "%bs": ["shadow_style"],
            "%bh": ["shadow_h"],
            "%bv": ["shadow_v"],
            "%bsb": ["shadow_blur"],
            "%bsp": ["shadow_spread"],
            "%bsc": ["shadow_color"],
            "%fa": ["font_alignment"],
            "%fs": ["font_size"],
            "%fc": ["font_color"],
            "%lh": ["line_height"],
            "%ls": ["letter_spacing"],
            "%ws": ["word_spacing"],
            "%ss": ["separator_style"],
            "%sw": ["separator_width"],
            "%sc": ["separator_color"],
            "padding_top": ["pt"],
            "padding_bottom": ["pb"],
            "padding_left": ["pl"],
            "padding_right": ["pr"],
            "greyout_color": ["grayout_color"],
            "greyout_blur": ["grayout_blur"],
        }
        for canonical_key, aliases in alias_map.items():
            canonical_present = canonical_key in seen
            alias_present = any(alias in seen for alias in aliases)
            if canonical_present or alias_present:
                _add_key(canonical_key)
                for alias_key in aliases:
                    _add_key(alias_key)

        return keys

    def _infer_element_type_from_style_id(self, style_id: Optional[str]) -> Optional[str]:
        """Best-effort style->element-type resolution from discovery/cache."""
        sid = str(style_id or "").strip()
        if not sid:
            return None

        def _extract_style_type(style_obj: Any) -> Optional[str]:
            if not isinstance(style_obj, dict):
                return None
            style_type = str(style_obj.get("%x") or style_obj.get("type") or "").strip()
            return style_type or None

        styles_data = self.discovery.data.get("styles", {}) if isinstance(self.discovery.data, dict) else {}
        if isinstance(styles_data, dict):
            direct = _extract_style_type(styles_data.get(sid))
            if direct:
                return direct
            for style_obj in styles_data.values():
                if not isinstance(style_obj, dict):
                    continue
                candidate_id = str(style_obj.get("id") or "").strip()
                if candidate_id == sid:
                    inferred = _extract_style_type(style_obj)
                    if inferred:
                        return inferred

        cached_styles = self._cli_cache.get("styles", {}) if isinstance(self._cli_cache, dict) else {}
        if isinstance(cached_styles, dict):
            direct = _extract_style_type(cached_styles.get(sid))
            if direct:
                return direct
            for style_obj in cached_styles.values():
                if not isinstance(style_obj, dict):
                    continue
                candidate_id = str(style_obj.get("id") or "").strip()
                if candidate_id == sid:
                    inferred = _extract_style_type(style_obj)
                    if inferred:
                        return inferred

        return None

    @staticmethod
    def _style_marker_prop_keys() -> List[str]:
        """
        `%p` keys that can keep Bubble's "style overridden" state sticky
        even after visual keys are reset.
        """
        return [
            "%s1",
            "style",
            "style_id",
            "style_name",
            "style_ref",
            "style_reference",
        ]

    def _queue_clear_style_marker_props(
        self,
        pb: PayloadBuilder,
        element_path: List[str],
        *,
        prop_updates: Optional[Dict[str, Any]] = None,
        extra_keys: Optional[List[str]] = None,
    ) -> None:
        """Clear style marker aliases stored under `%p` before assigning a new style."""
        if not isinstance(pb, PayloadBuilder):
            return
        blocked = {str(k) for k in (prop_updates or {}).keys()}
        keys: List[str] = list(self._style_marker_prop_keys())
        if isinstance(extra_keys, list):
            keys.extend(str(k) for k in extra_keys if str(k).strip())
        seen: set[str] = set()
        for key in keys:
            key_str = str(key or "").strip()
            if not key_str or key_str in seen or key_str in blocked:
                continue
            seen.add(key_str)
            pb.add_set_data(element_path + ["%p", key_str], None)

    def _prune_style_redundant_prop_updates(
        self,
        prop_updates: Dict[str, Any],
        *,
        element_type: Optional[str],
        style_id: Optional[str],
    ) -> None:
        """
        Remove style-driven prop updates that are equivalent to the target style.
        This avoids sticky "(overridden)" tags when callers pass style-default values.
        """
        if not isinstance(prop_updates, dict):
            return
        resolved_style = str(style_id or "").strip()
        if not resolved_style:
            return

        style_props = self._get_base_style_props(resolved_style)
        style_props = style_props if isinstance(style_props, dict) else {}
        style_override_keys = set(
            self._style_override_keys_for_element_type(element_type, target_style_id=resolved_style)
        )
        if not style_override_keys:
            return

        # Bubble defaults these style-driven booleans to false when absent in style %p.
        default_false_style_keys = {
            "crop_responsive",
            "background_size_cover",
            "center_background",
            "repeat_background_vertical",
            "repeat_background_horizontal",
            "%cb",
            "%rbv",
            "%rbh",
        }

        # Canonical/alias equivalence for value comparison.
        alias_groups: Dict[str, Tuple[str, ...]] = {
            "%cb": ("%cb", "center_background"),
            "%rbv": ("%rbv", "repeat_background_vertical"),
            "%rbh": ("%rbh", "repeat_background_horizontal"),
            "center_background": ("%cb", "center_background"),
            "repeat_background_vertical": ("%rbv", "repeat_background_vertical"),
            "repeat_background_horizontal": ("%rbh", "repeat_background_horizontal"),
            "%bas": ("%bas", "background_style", "bg_style"),
            "%bgc": ("%bgc", "background_color", "bg_color"),
            "%bgi": ("%bgi", "background_image", "bg_image"),
            "%bos": ("%bos", "border_style"),
            "%bw": ("%bw", "border_width"),
            "%bc": ("%bc", "border_color"),
            "%br": ("%br", "border_roundness", "border_radius"),
            "%bs": ("%bs", "shadow_style"),
            "%bh": ("%bh", "shadow_h"),
            "%bv": ("%bv", "shadow_v"),
            "%bsb": ("%bsb", "shadow_blur"),
            "%bsp": ("%bsp", "shadow_spread"),
            "%bsc": ("%bsc", "shadow_color"),
            "%fa": ("%fa", "font_alignment"),
            "%fs": ("%fs", "font_size"),
            "%fc": ("%fc", "font_color"),
            "%lh": ("%lh", "line_height"),
            "%ls": ("%ls", "letter_spacing"),
            "%ws": ("%ws", "word_spacing"),
            "padding_top": ("padding_top", "pt"),
            "padding_bottom": ("padding_bottom", "pb"),
            "padding_left": ("padding_left", "pl"),
            "padding_right": ("padding_right", "pr"),
        }

        removed: List[str] = []
        for key in list(prop_updates.keys()):
            key_str = str(key or "").strip()
            if not key_str or key_str not in style_override_keys:
                continue
            value = prop_updates.get(key)

            aliases = alias_groups.get(key_str, (key_str,))
            style_match_found = False
            for alias in aliases:
                if alias in style_props and style_props.get(alias) == value:
                    style_match_found = True
                    break
            if style_match_found:
                prop_updates.pop(key, None)
                removed.append(key_str)
                continue

            if key_str in default_false_style_keys and value is False:
                if not any(alias in style_props for alias in aliases):
                    prop_updates.pop(key, None)
                    removed.append(key_str)

        if removed:
            logger.info(
                "Pruned redundant style overrides (matching target style/defaults): "
                + ", ".join(sorted(set(removed)))
            )

    def _apply_element_updates(
        self,
        context_name: str,
        element_name: str,
        *,
        prop_updates: Dict[str, Any],
        style: Optional[str] = None,
        clear_style_override_keys: Optional[List[str]] = None,
        style_assign_props: Optional[Dict[str, Any]] = None,
        force_style_assign: bool = False,
        style_assign_with_set_data: bool = True,
        resolved_target: Optional[Tuple[str, str, Dict[str, Any]]] = None,
        dry_run: bool = False,
        prefer_last: bool = False,
        success_label: str = "element",
    ) -> bool:
        resolved = resolved_target
        if resolved is None:
            resolved = self._resolve_element_for_updates(
                context_name=context_name,
                element_name=element_name,
                prefer_last=prefer_last,
            )
        if not resolved:
            return False
        context_id, context_type, result = resolved
        path = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            str(result.get("id") or ((result.get("element") or {}).get("id") if isinstance(result.get("element"), dict) else "") or "").strip(),
        )
        pb = PayloadBuilder(appname=self.appname)

        element_obj = result.get("element", {}) if isinstance(result, dict) else {}
        element_type = str(element_obj.get("%x") or element_obj.get("type") or "").strip() or None

        resolved_style: Optional[str] = None

        if style is not None:
            raw_style = str(style).strip()
            if self._looks_like_style_id(raw_style, element_type=element_type):
                resolved_style = raw_style
            else:
                resolved_style = self._resolve_style_reference(
                    raw_style,
                    element_type=element_type,
                    strict=False,
                )
            if resolved_style is None:
                return False

            if not element_type:
                inferred_type = self._infer_element_type_from_style_id(resolved_style)
                if inferred_type:
                    element_type = inferred_type

            effective_clear_keys = clear_style_override_keys
            if effective_clear_keys is None and style_assign_props is None:
                effective_clear_keys = self._style_override_keys_for_element_type(
                    element_type,
                    target_style_id=resolved_style,
                )
            if effective_clear_keys:
                for key in effective_clear_keys:
                    key_str = str(key)
                    if key_str in prop_updates:
                        continue
                    pb.add_set_data(path + ["%p", key_str], None)
            self._queue_clear_style_marker_props(
                pb,
                path,
                prop_updates=prop_updates,
            )

            # For some element types (notably Alert), editor-consistent AssignStyle
            # payloads are required to clear stale override flags reliably.
            if force_style_assign or style_assign_props is not None:
                self._queue_style_assignment_changes(
                    pb,
                    path,
                    resolved_style,
                    style_props=style_assign_props,
                    include_set_data=style_assign_with_set_data,
                )
            else:
                pb.add_set_data(path + ["%s1"], resolved_style)

        for key, value in prop_updates.items():
            if value is None:
                continue
            pb.add_set_data(path + ["%p", key], value)

        if not pb.changes:
            logger.warning("No update fields were provided.")
            return True

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        try:
            self._dispatch_payload(pb)
            logger.success(f"Successfully updated {success_label}: '{element_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def _apply_surface_visual_updates(
        self,
        prop_updates: Dict[str, Any],
        *,
        raw_kwargs: Dict[str, Any],
        include_background: bool = False,
        include_border: bool = False,
        include_shadow: bool = False,
        include_alignment: bool = False,
        include_container_alignment: bool = False,
        include_padding: bool = False,
        include_margin: bool = False,
    ) -> bool:
        if include_background:
            if raw_kwargs.get("bg_style") is not None:
                prop_updates["%bas"] = str(raw_kwargs.get("bg_style")).strip()
            if raw_kwargs.get("bg_color") is not None:
                prop_updates["%bgc"] = self._resolve_color_arg(raw_kwargs.get("bg_color"))
            if raw_kwargs.get("bg_image") is not None:
                prop_updates["%bgi"] = {"%x": "TextExpression", "%e": {"0": str(raw_kwargs.get("bg_image"))}}
            gradient_input = {
                "gradient_color1": raw_kwargs.get("gradient_color1"),
                "gradient_color2": raw_kwargs.get("gradient_color2"),
                "gradient_mid": raw_kwargs.get("gradient_mid"),
                "gradient_style": raw_kwargs.get("gradient_style"),
                "gradient_direction": raw_kwargs.get("gradient_direction"),
                "gradient_shape": raw_kwargs.get("gradient_shape"),
                "gradient_size": raw_kwargs.get("gradient_size"),
                "gradient_xpos": raw_kwargs.get("gradient_xpos"),
                "gradient_ypos": raw_kwargs.get("gradient_ypos"),
                "gradient_angle": raw_kwargs.get("gradient_angle"),
            }
            if any(v is not None for v in gradient_input.values()):
                if raw_kwargs.get("bg_style") is None:
                    prop_updates["%bas"] = "gradient"
                try:
                    self._apply_gradient_background_options(prop_updates, gradient_input, allow_radial=True)
                except ValueError as e:
                    logger.error(str(e))
                    return False

        extra_props = raw_kwargs.get("extra_props")
        if isinstance(extra_props, dict):
            if include_border and extra_props.get("%bos") is not None and prop_updates.get("%bos") is None:
                prop_updates["%bos"] = extra_props.get("%bos")

        if include_border:
            if raw_kwargs.get("four_border_style") is not None:
                prop_updates["four_border_style"] = bool(raw_kwargs.get("four_border_style"))
            if raw_kwargs.get("border_style") is not None:
                prop_updates["%bos"] = str(raw_kwargs.get("border_style")).strip().lower()
            if raw_kwargs.get("border_width") is not None:
                prop_updates["%bw"] = int(raw_kwargs.get("border_width"))
            if raw_kwargs.get("border_color") is not None:
                prop_updates["%bc"] = raw_kwargs.get("border_color")
            if raw_kwargs.get("border_radius") is not None:
                radius = int(raw_kwargs.get("border_radius"))
                prop_updates["%br"] = radius
                prop_updates["border_roundness_top"] = radius
                prop_updates["border_roundness_right"] = radius
                prop_updates["border_roundness_bottom"] = radius
                prop_updates["border_roundness_left"] = radius
            if raw_kwargs.get("four_border_style") is None and raw_kwargs.get("border_type") is not None:
                prop_updates["four_border_style"] = str(raw_kwargs.get("border_type")) == "independent"
            for key in (
                "border_style_top",
                "border_style_bottom",
                "border_style_left",
                "border_style_right",
                "border_width_top",
                "border_width_bottom",
                "border_width_left",
                "border_width_right",
                "border_color_top",
                "border_color_bottom",
                "border_color_left",
                "border_color_right",
                "border_roundness_top",
                "border_roundness_right",
                "border_roundness_bottom",
                "border_roundness_left",
            ):
                if raw_kwargs.get(key) is not None:
                    value = raw_kwargs.get(key)
                    if key.startswith("border_width") or key.startswith("border_roundness"):
                        value = int(value)
                    prop_updates[key] = value

        if include_shadow:
            if raw_kwargs.get("shadow_style") is not None:
                prop_updates["%bs"] = raw_kwargs.get("shadow_style")
            if raw_kwargs.get("shadow_h") is not None:
                prop_updates["%bh"] = int(raw_kwargs.get("shadow_h"))
            if raw_kwargs.get("shadow_v") is not None:
                prop_updates["%bv"] = int(raw_kwargs.get("shadow_v"))
            if raw_kwargs.get("shadow_blur") is not None:
                prop_updates["%bsb"] = int(raw_kwargs.get("shadow_blur"))
            if raw_kwargs.get("shadow_spread") is not None:
                prop_updates["%bsp"] = int(raw_kwargs.get("shadow_spread"))
            if raw_kwargs.get("shadow_color") is not None:
                prop_updates["%bsc"] = raw_kwargs.get("shadow_color")

        if include_alignment:
            if raw_kwargs.get("horiz_alignment") is not None:
                prop_updates["horiz_alignment"] = raw_kwargs.get("horiz_alignment")
            if raw_kwargs.get("vert_alignment") is not None:
                prop_updates["vert_alignment"] = raw_kwargs.get("vert_alignment")
            if raw_kwargs.get("nonant_alignment") is not None:
                prop_updates["nonant_alignment"] = raw_kwargs.get("nonant_alignment")

        if include_container_alignment:
            if raw_kwargs.get("container_horiz_alignment") is not None:
                prop_updates["container_horiz_alignment"] = raw_kwargs.get("container_horiz_alignment")
            if raw_kwargs.get("container_vert_alignment") is not None:
                prop_updates["container_vert_alignment"] = raw_kwargs.get("container_vert_alignment")

        if include_padding:
            if raw_kwargs.get("padding_top") is not None:
                prop_updates["padding_top"] = int(raw_kwargs.get("padding_top"))
            if raw_kwargs.get("padding_bottom") is not None:
                prop_updates["padding_bottom"] = int(raw_kwargs.get("padding_bottom"))
            if raw_kwargs.get("padding_left") is not None:
                prop_updates["padding_left"] = int(raw_kwargs.get("padding_left"))
            if raw_kwargs.get("padding_right") is not None:
                prop_updates["padding_right"] = int(raw_kwargs.get("padding_right"))

        if include_margin:
            if raw_kwargs.get("margin_top") is not None:
                prop_updates["margin_top"] = int(raw_kwargs.get("margin_top"))
            if raw_kwargs.get("margin_bottom") is not None:
                prop_updates["margin_bottom"] = int(raw_kwargs.get("margin_bottom"))
            if raw_kwargs.get("margin_left") is not None:
                prop_updates["margin_left"] = int(raw_kwargs.get("margin_left"))
            if raw_kwargs.get("margin_right") is not None:
                prop_updates["margin_right"] = int(raw_kwargs.get("margin_right"))

        return True

