                if isinstance(value, dict) and value.get("%x") == "TextExpression":
                    expr = value
                elif (
                    isinstance(value, dict)
                    and value.get("type") == "TextExpression"
                    and isinstance(value.get("entries"), dict)
                ):
                    expr = {"%x": "TextExpression", "%e": dict(value.get("entries") or {})}
                elif value in (None, ""):
                    expr = None
                elif isinstance(value, dict):
                    expr = {"%x": "TextExpression", "%e": {"0": "", "1": value, "2": ""}}
                else:
                    expr = {"%x": "TextExpression", "%e": {"0": str(value)}}

                canonical = None
                if isinstance(expr, dict) and expr.get("%x") == "TextExpression":
                    canonical = {"type": "TextExpression", "entries": dict(expr.get("%e") or {})}
                return expr, canonical

