    def update_radio(
        self,
        context_name: str,
        element_name: str,
        *,
        label: Optional[str] = None,
        group_name: Optional[str] = None,
        choices_str: Optional[str] = None,
        dynamic_type: Optional[str] = None,
        result_type: Optional[str] = None,
        query_source_type: Optional[str] = None,
        result_from_field: Optional[str] = None,
        constraints_json: Optional[str] = None,
        sort_field: Optional[str] = None,
        sort_desc: bool = False,
        ignore_empty_constraints: bool = False,
        choices_source_json: Optional[str] = None,
        option_caption_field: Optional[str] = None,
        required: Optional[bool] = None,
        auto_binding: Optional[bool] = None,
        bind_field: Optional[str] = None,
        disabled: Optional[bool] = None,
        default_value: Any = None,
        columns: Optional[int] = None,
        use_dynamic_columns: Optional[bool] = None,
        min_column_width_px: Optional[int] = None,
        color: Optional[str] = None,
        selected: Optional[bool] = None,
        style: Optional[str] = None,
        width: Any = None,
        height: Any = None,
        min_width: Any = None,
        max_width: Any = None,
        fixed_width: Optional[bool] = None,
        fit_width: Optional[bool] = None,
        min_height: Any = None,
        max_height: Any = None,
        fixed_height: Optional[bool] = None,
        fit_height: Optional[bool] = None,
        is_visible: Optional[bool] = None,
        collapse_when_hidden: Optional[bool] = None,
        html_id: Optional[str] = None,
        unique_id: Optional[str] = None,
        dry_run: bool = False,
        prefer_last: bool = False,
    ) -> bool:
        context_id, context_type = self._find_context(context_name)
        if not context_id:
            logger.error(f"Context '{context_name}' not found.")
            return False

        prop_updates: Dict[str, Any] = {}
        if label is not None:
            prop_updates["%lab"] = {"%x": "TextExpression", "%e": {"0": str(label)}}
        if group_name is not None:
            prop_updates["radio_group"] = str(group_name)
        if choices_str is not None:
            prop_updates["choices_style"] = "static"
            prop_updates["%ch"] = str(choices_str).replace(",", "\n")
        resolved_result_type_ref = str(result_type or dynamic_type or "").strip()
        has_query_builder_inputs = any(
            [
                bool(str(query_source_type or "").strip()),
                bool(str(result_from_field or "").strip()),
                bool(str(constraints_json or "").strip()),
                bool(str(sort_field or "").strip()),
                bool(ignore_empty_constraints),
                bool(sort_desc),
            ]
        )
        choice_type = self._resolve_bubble_type_id(resolved_result_type_ref or "text")
        if resolved_result_type_ref or choices_source_json or has_query_builder_inputs:
            prop_updates["choices_style"] = "dynamic"
            prop_updates["dynamic_type"] = choice_type

            try:
                resolved_source_expr = self._resolve_direct_data_source_expression(
                    data_source=choices_source_json,
                    result_type=resolved_result_type_ref,
                    context_id=context_id,
                    context_type=context_type,
                    message_name="get_group_data",
                    source_label="choices_source_json",
                    allow_current_cell=False,
                )
            except ValueError as e:
                logger.error(str(e))
                return False

            if isinstance(resolved_source_expr, dict):
                try:
                    resolved_source_expr = self._apply_search_expression_overrides(
                        resolved_source_expr,
                        context_id=context_id,
                        context_type=context_type,
                        default_source_type=choice_type,
                        query_source_type=query_source_type,
                        constraints_json=constraints_json,
                        sort_field=sort_field,
                        sort_desc=sort_desc,
                        ignore_empty_constraints=ignore_empty_constraints,
                    )
                except ValueError as e:
                    logger.error(str(e))
                    return False
                prop_updates["%ds"] = resolved_source_expr
                if not resolved_result_type_ref:
                    source_expr = str(resolved_source_expr.get("%x") or "").strip()
                    source_payload = (
                        resolved_source_expr.get("%p")
                        if isinstance(resolved_source_expr.get("%p"), dict)
                        else {}
                    )
                    if source_expr == "AllOptionValue":
                        opt_ref = str(source_payload.get("option_set") or "").strip()
                        if opt_ref:
                            choice_type = opt_ref
                    elif source_expr == "Search":
                        source_type = str(source_payload.get("%t5") or "").strip()
                        if source_type:
                            choice_type = source_type
            elif resolved_source_expr is not None:
                logger.error("choices_source_json JSON must be an object expression.")
                return False
            else:
                resolved_query_source_type = self._resolve_bubble_type_id(
                    str(query_source_type or "").strip() or choice_type
                )
                relation_field = str(result_from_field or "").strip()
                if not relation_field and resolved_query_source_type != choice_type:
                    inferred_relation = self._infer_relation_field(resolved_query_source_type, choice_type)
                    if inferred_relation:
                        relation_field = inferred_relation
                        logger.info(
                            f"Auto-mapped result_from_field: {resolved_query_source_type} -> {choice_type} via '{relation_field}'."
                        )
                if query_source_type and resolved_query_source_type != choice_type and not relation_field:
                    logger.error(
                        "query_source_type differs from result_type but result_from_field is missing. "
                        "Provide --result-from-field."
                    )
                    return False

                resolved_sort_field = str(sort_field or "").strip()
                if resolved_sort_field:
                    resolved_sort_field = self._resolve_type_field_key_or_raw(
                        resolved_query_source_type,
                        resolved_sort_field,
                        label="sort_field",
                    )
                try:
                    parsed_constraints = self._parse_constraints_input(
                        constraints_json,
                        resolved_query_source_type,
                        context_id=context_id,
                        context_type=context_type,
                    )
                except ValueError as e:
                    logger.error(str(e))
                    return False
                try:
                    source_expr = build_search_source_expression(
                        query_source_type=resolved_query_source_type,
                        constraints=parsed_constraints,
                        ignore_empty_constraints=True if ignore_empty_constraints else None,
                        sort_field=resolved_sort_field or None,
                        sort_desc=bool(sort_desc) if resolved_sort_field else None,
                        dynamic_sort_field=None if resolved_sort_field else None,
                        result_from_field=relation_field or None,
                    )
                except ValueError as e:
                    logger.error(f"Failed to build source query JSON: {e}")
                    return False
                prop_updates["%ds"] = source_expr

            if option_caption_field:
                resolved_caption = self._resolve_type_field_key_or_raw(
                    choice_type,
                    str(option_caption_field),
                    label="option_caption_field",
                )
                prop_updates["option_display_expression"] = {
                    "%x": "TextExpression",
                    "%e": {
                        "0": "",
                        "1": {
                            "%x": "InjectedValue",
                            "%n": {
                                "%x": "Message",
                                "%nm": resolved_caption,
                                "%n": None,
                                "%a": None,
                                "is_slidable": False,
                            },
                        },
                        "2": "",
                    },
                }

        if required is not None:
            prop_updates["%1m"] = bool(required)
        if auto_binding is not None:
            prop_updates["auto_binding"] = bool(auto_binding)
        if bind_field is not None:
            prop_updates["bind_field"] = str(bind_field)
        if disabled is not None:
            prop_updates["disabled"] = bool(disabled)
        if default_value is not None:
            try:
                resolved_default_value = self._resolve_radio_default_value(
                    default_value,
                    choice_type=choice_type,
                    context_id=context_id,
                    context_type=context_type,
                    source_label="default_value",
                )
            except ValueError as e:
                logger.error(str(e))
                return False
            prop_updates["%d1"] = resolved_default_value
        if columns is not None:
            prop_updates["%c5"] = int(columns)
        if use_dynamic_columns is not None:
            prop_updates["use_dynamic_columns"] = bool(use_dynamic_columns)
        if min_column_width_px is not None:
            prop_updates["min_column_width_px"] = int(min_column_width_px)
        if color is not None:
            prop_updates["color"] = str(color).strip().lower()
        if selected is not None:
            prop_updates["selected"] = bool(selected)

        self._apply_dimension_updates(
            prop_updates,
            width=width,
            height=height,
            min_width=min_width,
            max_width=max_width,
            fixed_width=fixed_width,
            fit_width=fit_width,
            min_height=min_height,
            max_height=max_height,
            fixed_height=fixed_height,
            fit_height=fit_height,
            include_fit=True,
            set_wh_ints=True,
        )
        self._apply_global_element_updates(
            prop_updates,
            is_visible=is_visible,
            collapse_when_hidden=collapse_when_hidden,
            html_id=html_id,
            unique_id=unique_id,
        )
        return self._apply_element_updates(
            context_name,
            element_name,
            prop_updates=prop_updates,
            style=style,
            dry_run=dry_run,
            prefer_last=prefer_last,
            success_label="radio",
        )

    def delete_radio(
        self,
        context_name: str,
        element_name: str,
        dry_run: bool = False,
        prefer_last: bool = False,
    ) -> bool:
        resolved = self._resolve_element_for_updates(
            context_name=context_name,
            element_name=element_name,
            prefer_last=prefer_last,
        )
        if not resolved:
            return False
        context_id, context_type, result = resolved

        element_obj = result.get("element", {}) if isinstance(result, dict) else {}
        element_type = str(element_obj.get("%x") or element_obj.get("type") or "").strip().lower()
        if element_type and element_type not in {"radiobuttons", "radiobutton"}:
            logger.error(f"Element '{element_name}' is type '{element_type}', expected 'radiobuttons'.")
            return False

        target_id = str(result.get("id") or element_obj.get("id") or "").strip()
        path_array = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            target_id,
        )
        if not target_id:
            _, token = self._find_last_element_token(path_array)
            target_id = str(token or "").strip()
        if not target_id:
            logger.error(f"Could not resolve element id for '{element_name}'.")
            return False

        pb = PayloadBuilder(appname=self.appname)
        pb.add_update_index(["_index", "id_to_path", target_id], None)
        pb.changes.append(
            {
                "intent": {
                    "name": "RemoveElement",
                    "id": random.randint(1, 999999),
                    "intent_details": {
                        "user_action": "Keyboard Press Delete",
                        "selected_element": target_id,
                    },
                    "source_appname": "",
                },
                "path_array": path_array,
                "body": None,
                "version_control_api_version": 4,
                "changelog_data": [],
                "session_id": pb.session_id,
            }
        )

        parent_updates = self._find_issues_sub_parents_for_child(target_id)
        if not parent_updates:
            fallback_parent = None
            fallback_children: List[str] = []
            if len(path_array) >= 2:
                parent_path = path_array[:-2]
                parent_node = self._get_value_at_path(parent_path)
                fallback_parent = str(parent_node.get("id") or "").strip() if isinstance(parent_node, dict) else None
                if fallback_parent:
                    fallback_children = self._child_ids_from_node(parent_node)
            if not fallback_parent:
                fallback_parent = (
                    self._resolve_context_object_id_from_index(context_id, context_type)
                    or self._lookup_cached_context_object_id(context_type, context_id)
                )
                if fallback_parent:
                    try:
                        root_node = self.discovery._get_context_root(context_id, context_type)
                    except Exception:
                        root_node = None
                    fallback_children = self._child_ids_from_node(root_node)
                    if not fallback_children:
                        fallback_children = self._root_child_ids_from_index(context_id, context_type)
            if fallback_parent:
                parent_updates = [(fallback_parent, fallback_children)]
        for parent_id, children in parent_updates:
            updated = [cid for cid in children if str(cid) != target_id]
            pb.add_update_index(["_index", "issues_sub", str(parent_id)], json.dumps(updated))

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        try:
            self._dispatch_payload(pb)
            self._remove_cached_element_aliases(
                context_id=context_id,
                context_type=context_type,
                element_id=target_id,
                element_path=result.get("path") if isinstance(result.get("path"), list) else None,
            )
            logger.success(f"Successfully deleted radio: '{element_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

    def update_slider(
        self,
        context_name: str,
        element_name: str,
        *,
        min_value: Optional[float] = None,
        max_value: Optional[float] = None,
        initial_value: Optional[float] = None,
        range_initial_value: Any = None,
        initial_range_value: Any = None,
        step: Optional[float] = None,
        range_type: Optional[str] = None,
        orientation: Optional[str] = None,
        background_color: Optional[str] = None,
        handle_color: Optional[str] = None,
        range_area_color: Optional[str] = None,
        style: Optional[str] = None,
        width: Any = None,
        height: Any = None,
        min_width: Any = None,
        max_width: Any = None,
        fixed_width: Optional[bool] = None,
        fit_width: Optional[bool] = None,
        min_height: Any = None,
        max_height: Any = None,
        fixed_height: Optional[bool] = None,
        fit_height: Optional[bool] = None,
        is_visible: Optional[bool] = None,
        collapse_when_hidden: Optional[bool] = None,
        html_id: Optional[str] = None,
        unique_id: Optional[str] = None,
        dry_run: bool = False,
        prefer_last: bool = False,
    ) -> bool:
        prop_updates: Dict[str, Any] = {}
        if range_initial_value is None and initial_range_value is not None:
            range_initial_value = initial_range_value
        if min_value is not None:
            prop_updates["min_value"] = float(min_value)
        if max_value is not None:
            prop_updates["max_value"] = float(max_value)
        if initial_value is not None:
            prop_updates["%v"] = float(initial_value)
            prop_updates["%c1"] = float(initial_value)
        if range_initial_value is not None:
            context_id, context_type = self._find_context(context_name)
            if not context_id:
                logger.error(f"'{context_name}' not found")
                return False
            prop_updates["%c1"] = self._normalize_slider_range_initial_value(
                range_initial_value,
                context_id=context_id,
                context_type=context_type,
            )
            prop_updates.pop("%v", None)
        if step is not None:
            prop_updates["step"] = float(step)
        if range_type is not None:
            prop_updates["range_type"] = str(range_type).strip().lower()
        if orientation is not None:
            prop_updates["orientation"] = str(orientation).strip().lower()
        if background_color is not None:
            prop_updates["background_color"] = self._resolve_color_arg(background_color)
        if handle_color is not None:
            prop_updates["handle_color"] = self._resolve_color_arg(handle_color)
        if range_area_color is not None:
            prop_updates["range_area_color"] = self._resolve_color_arg(range_area_color)
        self._apply_dimension_updates(
            prop_updates,
            width=width,
            height=height,
            min_width=min_width,
            max_width=max_width,
            fixed_width=fixed_width,
            fit_width=fit_width,
            min_height=min_height,
            max_height=max_height,
            fixed_height=fixed_height,
            fit_height=fit_height,
            include_fit=False,
            set_wh_ints=True,
        )
        self._apply_global_element_updates(
            prop_updates,
            is_visible=is_visible,
            collapse_when_hidden=collapse_when_hidden,
            html_id=html_id,
            unique_id=unique_id,
        )
        return self._apply_element_updates(
            context_name,
            element_name,
            prop_updates=prop_updates,
            style=style,
            dry_run=dry_run,
            prefer_last=prefer_last,
            success_label="slider",
        )

    def delete_slider(
        self,
        context_name: str,
        element_name: str,
        dry_run: bool = False,
        prefer_last: bool = False,
    ) -> bool:
        resolved = self._resolve_element_for_updates(
            context_name=context_name,
            element_name=element_name,
            prefer_last=prefer_last,
        )
        if not resolved:
            return False
        context_id, context_type, result = resolved

        element_obj = result.get("element", {}) if isinstance(result, dict) else {}
        element_type = str(element_obj.get("%x") or element_obj.get("type") or "").strip().lower()
        if element_type and element_type != "sliderinput":
            logger.error(f"Element '{element_name}' is type '{element_type}', expected 'sliderinput'.")
            return False

        target_id = str(result.get("id") or element_obj.get("id") or "").strip()
        path_array = self._resolve_canonical_existing_element_path(
            context_id,
            context_type,
            result,
            target_id,
        )
        if not target_id:
            _, token = self._find_last_element_token(path_array)
            target_id = str(token or "").strip()
        if not target_id:
            logger.error(f"Could not resolve element id for '{element_name}'.")
            return False

        pb = PayloadBuilder(appname=self.appname)
        pb.add_update_index(["_index", "id_to_path", target_id], None)
        pb.changes.append(
            {
                "intent": {
                    "name": "RemoveElement",
                    "id": random.randint(1, 999999),
                    "intent_details": {
                        "user_action": "Keyboard Press Delete",
                        "selected_element": target_id,
                    },
                    "source_appname": "",
                },
                "path_array": path_array,
                "body": None,
                "version_control_api_version": 4,
                "changelog_data": [],
                "session_id": pb.session_id,
            }
        )

        parent_updates = self._find_issues_sub_parents_for_child(target_id)
        if not parent_updates:
            fallback_parent = None
            fallback_children: List[str] = []
            if len(path_array) >= 2:
                parent_path = path_array[:-2]
                parent_node = self._get_value_at_path(parent_path)
                fallback_parent = str(parent_node.get("id") or "").strip() if isinstance(parent_node, dict) else None
                if fallback_parent:
                    fallback_children = self._child_ids_from_node(parent_node)
            if not fallback_parent:
                fallback_parent = (
                    self._resolve_context_object_id_from_index(context_id, context_type)
                    or self._lookup_cached_context_object_id(context_type, context_id)
                )
                if fallback_parent:
                    try:
                        root_node = self.discovery._get_context_root(context_id, context_type)
                    except Exception:
                        root_node = None
                    fallback_children = self._child_ids_from_node(root_node)
                    if not fallback_children:
                        fallback_children = self._root_child_ids_from_index(context_id, context_type)
            if fallback_parent:
                parent_updates = [(fallback_parent, fallback_children)]
        for parent_id, children in parent_updates:
            updated = [cid for cid in children if str(cid) != target_id]
            pb.add_update_index(["_index", "issues_sub", str(parent_id)], json.dumps(updated))

        if dry_run:
            logger.info("\n DRY RUN - Payload preview:")
            logger.log(pb.to_json())
            return True

        try:
            self._dispatch_payload(pb)
            self._remove_cached_element_aliases(
                context_id=context_id,
                context_type=context_type,
                element_id=target_id,
                element_path=result.get("path") if isinstance(result.get("path"), list) else None,
            )
            logger.success(f"Successfully deleted slider: '{element_name}'")
            return True
        except Exception as e:
            logger.error(f"Failed to send: {e}")
            return False

