        if normalized_kwargs.get("constraints_json") is None and normalized_kwargs.get("query_constraints_json") is not None:
            normalized_kwargs["constraints_json"] = normalized_kwargs.get("query_constraints_json")
        if normalized_kwargs.get("sort_field") is None and normalized_kwargs.get("query_sort_field") is not None:
            normalized_kwargs["sort_field"] = normalized_kwargs.get("query_sort_field")
        if normalized_kwargs.get("sort_desc") is None and normalized_kwargs.get("query_sort_desc") is not None:
            normalized_kwargs["sort_desc"] = normalized_kwargs.get("query_sort_desc")
        if (
            normalized_kwargs.get("ignore_empty_constraints") is None
            and normalized_kwargs.get("query_ignore_empty_constraints") is not None
        ):
            normalized_kwargs["ignore_empty_constraints"] = normalized_kwargs.get("query_ignore_empty_constraints")
        if normalized_kwargs.get("reference_element") is None and normalized_kwargs.get("reference") is not None:
            normalized_kwargs["reference_element"] = normalized_kwargs.get("reference")

        update_group_params = set(inspect.signature(self.update_group).parameters.keys())
        update_group_params.discard("self")
        update_group_params.discard("context_name")
        update_group_params.discard("element_name")
        forward_kwargs = {
            k: v
            for k, v in normalized_kwargs.items()
            if k in update_group_params
        }
        return self.update_group(
            context_name=context_name,
            element_name=element_name,
            assume_group_focus=True,
            dry_run=dry_run,
            prefer_last=prefer_last,
            **forward_kwargs,
        )

