        border_color: Optional[str] = None,
        border_radius: Optional[int] = None,
        border_style_top: Optional[str] = None,
        border_style_bottom: Optional[str] = None,
        border_style_left: Optional[str] = None,
        border_style_right: Optional[str] = None,
        border_width_top: Optional[int] = None,
