        if attach_to is None and kwargs.get("attach_to") is not None:
            attach_to = kwargs.pop("attach_to")
        if limit_image_width is None and kwargs.get("limit_image_width") is not None:
            limit_image_width = bool(kwargs.pop("limit_image_width"))
        if limit_image_width is None and kwargs.get("limit_image_size_before_upload") is not None:
            limit_image_width = bool(kwargs.pop("limit_image_size_before_upload"))
        legacy_max_file_size = None
        if legacy_max_file_size is None and kwargs.get("max_file_size_mb") is not None:
            legacy_max_file_size = kwargs.pop("max_file_size_mb")
        if legacy_max_file_size is None and kwargs.get("max_size") is not None:
            legacy_max_file_size = kwargs.pop("max_size")
        if legacy_max_file_size is None and kwargs.get("max_file_size") is not None:
            legacy_max_file_size = kwargs.pop("max_file_size")
        if limit_image_width is None and legacy_max_file_size is not None:
            logger.warning(
                "PictureInput does not support max_file_size_mb/max_size. "
                "Enabling limit_image_width instead."
            )
            limit_image_width = True
        if kwargs.get("placeholder") is not None:
            placeholder_label = str(kwargs.pop("placeholder"))
            if str(label or "").strip() in {"", "Upload picture", "Upload image"}:
                label = placeholder_label

        def _parse_expr_maybe(value: Any, label_name: str) -> Any:
            if value is None:
                return None
            if isinstance(value, (dict, list, int, float, bool)):
                return value
            raw = str(value).strip()
            if not raw:
                return None
            if raw.startswith("{") or raw.startswith("["):
                parsed = self._parse_json_arg(raw, label_name)
                if parsed is not None:
                    return parsed
            return value

        dynamic_link = _parse_expr_maybe(dynamic_link, "dynamic_link")
        attach_to = _parse_expr_maybe(attach_to, "attach_to")

        supported_props = self._supported_properties_for_tool("create_picture_uploader")
        kwargs = self._trim_kwargs_to_capabilities("create_picture_uploader", kwargs)
        if "fit_width" not in supported_props:
            fit_width = False
        if "fit_height" not in supported_props:
            fit_height = False
        if not self._apply_common_surface_kwargs(
            kwargs,
            dry_run=dry_run,
            supported_props=supported_props,
            normalize_alignment=True,
        ):
            return False
        kwargs.pop("all_4_borders", None)
        kwargs.pop("border_type", None)

        if auto_binding is not None:
            kwargs["auto_binding"] = bool(auto_binding)
        if bind_field is not None:
            kwargs["bind_field"] = str(bind_field)
        if dynamic_link is not None:
            kwargs["dynamic_link"] = dynamic_link
        if private_file is not None:
            kwargs["private_file"] = bool(private_file)
        if attach_to is not None:
            kwargs["attach_to"] = attach_to
