    def create_thing(self, context_name: str, element_name: str, type_name: str, fields: Dict[str, str], event: str = "click", dry_run: bool = False) -> bool:
        """Create a new thing using inputs"""
        print(f" Searching for context: {context_name}")
        context_id, context_type = self._find_context(context_name)
        if not context_id: return False

        if element_name == "Page":
            element = {'id': context_id}
        else:
            element = self.discovery.find_element_by_name(context_id, element_name, context_type)
            if not element: print(f"❌ Trigger element '{element_name}' not found"); return False

        wf_info = self.discovery.find_workflow_for_element(context_id, element['id'], event, context_type)
        if not wf_info: print(f"❌ No workflow found for '{element_name}'. Create one first."); return False

        # Resolve Fields (Map "Input Name's value" -> expression logic)
        resolved_fields = {}
        for key, val_expression in fields.items():
             # Basic heuristic: if value looks like "Input X", find element ID
             # For now, simplistic: "Input Name" -> find element -> construct value expression
             # If just string, use static text?
             # Let's assume input maps for now as that's the requirement.

             # If value comes from parser as "Input Name", we resolve it
             input_el = self.discovery.find_element_by_name(context_id, val_expression, context_type)
             if input_el:
                 resolved_fields[key] = {
                     "%x": "TextExpression",
                     "%e": {"0": {"%x": "ElementParent", "%n": {"%nm": "value_text", "%e": input_el['id']}}}
                 }
             else:
                 # Static fallback
                 resolved_fields[key] = {
                     "%x": "TextExpression",
                     "%e": {"0": val_expression}
                 }

        from bubble_sdk import ActionBuilder
        ab = ActionBuilder()
        new_index = self._get_next_action_index(wf_info['workflow'])

        action_payload = ab.create_thing(new_index, type_name, resolved_fields)

        wf_key = self._resolve_workflow_key_from_info(context_id, context_type, wf_info)
        if not wf_key:
            print("❌ Could not resolve workflow key")
            return False
        return self._inject_action(context_id, wf_key, new_index, action_payload, f"Create {type_name}", dry_run)

