    argv = sys.argv[1:]
    if argv and argv[0] == 'natural:':
        argv[0] = 'natural'
    args = parser.parse_args(argv)
    print(f"[DEBUG] CLI args.profile: {getattr(args, 'profile', 'MISSING')}")

    if not args.command:
        parser.print_help()
        sys.exit(1)

    script_dir = os.path.dirname(os.path.abspath(__file__))

    # Resolve settings path robustly so CLI works even when run outside project cwd.
    settings_path = args.settings
    if not os.path.isabs(settings_path):
        candidate_cwd = os.path.abspath(settings_path)
        candidate_script = os.path.join(script_dir, settings_path)
        if os.path.exists(candidate_cwd):
            settings_path = candidate_cwd
        elif os.path.exists(candidate_script):
            settings_path = candidate_script
        else:
            # Keep as-is; loader will return empty settings if not found.
            settings_path = candidate_cwd

    settings = load_settings_file(settings_path)
    profile_cfg = resolve_profile(settings, args.profile)
    if getattr(args, "profile", None) and not profile_cfg.get("name"):
        available_profiles = []
        raw_profiles = settings.get("profiles") if isinstance(settings, dict) else None
        if isinstance(raw_profiles, dict):
            available_profiles = sorted(str(k) for k in raw_profiles.keys())
        if available_profiles:
            logger.error(
                f"Profile '{args.profile}' not found. Available profiles: {', '.join(available_profiles)}"
            )
        else:
            logger.error(
                f"Profile '{args.profile}' not found and no profiles are configured in settings."
            )
        sys.exit(1)
    # Extract app_json_path - respect explicitly set None or empty string
    if "app_json_path" in profile_cfg:
        app_json_path_raw = profile_cfg["app_json_path"]
    else:
        app_json_path_raw = os.getenv("BUBBLE_CLI_APP_JSON", "src/app.bubble")

    app_json_path = app_json_path_raw
    if app_json_path and not os.path.isabs(app_json_path):
        settings_base_dir = os.path.dirname(os.path.abspath(settings_path)) if settings_path else script_dir
        candidate_from_settings = os.path.join(settings_base_dir, app_json_path)
        candidate_from_script = os.path.join(script_dir, app_json_path)
        if os.path.exists(candidate_from_settings):
            app_json_path = candidate_from_settings
        elif os.path.exists(candidate_from_script):
            app_json_path = candidate_from_script
        else:
            # Prefer settings-relative path for consistency even if file is currently missing.
            app_json_path = candidate_from_settings
    appname = profile_cfg.get("appname") or os.getenv("BUBBLE_CLI_APPNAME")
    webhook_url = profile_cfg.get("webhook_url") or os.getenv("BUBBLE_CLI_WEBHOOK_URL")

    nl_config = {
        "openai_api_key": profile_cfg.get("openai_api_key") or os.getenv("OPENAI_API_KEY"),
        "nl_ai": profile_cfg.get("nl_ai") if profile_cfg.get("nl_ai") is not None else os.getenv("BUBBLE_CLI_NL_AI"),
        "nl_model": profile_cfg.get("nl_model") or os.getenv("BUBBLE_CLI_NL_MODEL"),
        "nl_regex_min": profile_cfg.get("nl_regex_min") or os.getenv("BUBBLE_CLI_NL_REGEX_MIN", "0.7"),
        "nl_log": profile_cfg.get("nl_log") if profile_cfg.get("nl_log") is not None else os.getenv("BUBBLE_CLI_NL_LOG"),
        "nl_log_path": profile_cfg.get("nl_log_path") or os.getenv("BUBBLE_CLI_NL_LOG_PATH", "logs/nl_samples.jsonl"),
        "settings_path": settings_path,
    }

    render_config = {
        "render_endpoint": profile_cfg.get("render_endpoint") or os.getenv("BUBBLE_CLI_RENDER_ENDPOINT"),
        "renderer_mode": profile_cfg.get("renderer_mode") or os.getenv("BUBBLE_CLI_RENDERER_MODE"),
        "rendered_html_default": profile_cfg.get("rendered_html_default"),
        "render_timeout_ms": profile_cfg.get("render_timeout_ms") or os.getenv("BUBBLE_CLI_RENDER_TIMEOUT_MS"),
        "allow_render_fallback": profile_cfg.get("allow_render_fallback"),
        "auto_install_local_renderer": profile_cfg.get("auto_install_local_renderer"),
        "node_bin": profile_cfg.get("node_bin") or os.getenv("BUBBLE_CLI_NODE_BIN"),
        "npm_bin": profile_cfg.get("npm_bin") or os.getenv("BUBBLE_CLI_NPM_BIN")
    }

    # Extract and resolve consolelog_json_path
    consolelog_json_path_raw = profile_cfg.get("consolelog_json_path")
